from dataclasses import dataclass, field
from typing import Any, Protocol, runtime_checkable


@dataclass
class ComponentSpec:
    id: str
    version: str
    category: str  # orchestration | tool | memory | safety | observability | infra
    owner: str
    responsibilities: list[str]
    required_dependencies: list[str] = field(default_factory=list)
    optional_dependencies: list[str] = field(default_factory=list)
    sla: dict[str, Any] = field(default_factory=dict)


@runtime_checkable
class Component(Protocol):
    spec: ComponentSpec

    def health_check(self) -> dict[str, Any]:
        # Return {"healthy": bool, "details": {...}}
        ...


class ComponentRegistry:
    # Central registry of all blueprint components in a deployment.
    # Components self-register; the registry validates dependency graphs.

    def __init__(self):
        self._specs: dict[str, ComponentSpec] = {}
        self._instances: dict[str, Component] = {}

    def register_spec(self, spec: ComponentSpec) -> None:
        if spec.id in self._specs:
            raise ValueError(f"Component already registered: {spec.id}")
        self._specs[spec.id] = spec

    def register_instance(self, component_id: str, instance: Component) -> None:
        if component_id not in self._specs:
            raise ValueError(f"No spec registered for: {component_id}")
        self._instances[component_id] = instance

    def validate_dependencies(self) -> list[str]:
        # Return list of dependency violations
        violations = []
        registered = set(self._specs.keys())
        for spec in self._specs.values():
            for dep in spec.required_dependencies:
                if dep not in registered:
                    violations.append(
                        f"{spec.id} requires {dep} but it is not registered"
                    )
        return violations

    def dependency_order(self) -> list[str]:
        # Topological sort: returns component IDs in startup order
        in_degree: dict[str, int] = {cid: 0 for cid in self._specs}
        dependents: dict[str, list[str]] = {cid: [] for cid in self._specs}
        for spec in self._specs.values():
            for dep in spec.required_dependencies:
                if dep in in_degree:
                    in_degree[spec.id] += 1
                    dependents[dep].append(spec.id)
        queue = [cid for cid, deg in in_degree.items() if deg == 0]
        order = []
        while queue:
            cid = queue.pop(0)
            order.append(cid)
            for dep in dependents[cid]:
                in_degree[dep] -= 1
                if in_degree[dep] == 0:
                    queue.append(dep)
        if len(order) != len(self._specs):
            raise RuntimeError("Circular dependency detected in component graph")
        return order

    def health_report(self) -> dict[str, Any]:
        results = {}
        for cid, instance in self._instances.items():
            try:
                results[cid] = instance.health_check()
            except Exception as exc:
                results[cid] = {"healthy": False, "error": str(exc)}
        all_healthy = all(r.get("healthy", False) for r in results.values())
        return {"all_healthy": all_healthy, "components": results}

    def list_by_category(self, category: str) -> list[ComponentSpec]:
        return [s for s in self._specs.values() if s.category == category]
